// ---------------------------------------------------------------------------
// Admin Product Catalog  —  Server Component
//
// Goals:
//  • Read-heavy browsing  —  data is cached under the "products" tag so
//    day-to-day navigation never blocks on a fresh query.
//  • Non-blocking sync   —  the "Sync Latest Catalog" form uses an inline
//    Server Action that invalidates the cache and kicks off a background
//    ERP/PIM refresh, then returns immediately.
//  • Eventual consistency —  the product list may be briefly stale after a
//    sync.  Once the background job finishes, the cache is invalidated again
//    so the next page visit picks up the fresh data.
// ---------------------------------------------------------------------------

import { revalidateTag } from "next/cache";
import { getCachedProducts, syncFromERP } from "@/lib/db";
import { SyncForm } from "./sync-form";

// ── Inline Server Action ─────────────────────────────────────────────────

async function syncCatalog() {
  "use server";

  // 1. Immediately invalidate the "products" cache tag so subsequent reads
  //    fetch the current database state (even if the ERP sync hasn't run).
  revalidateTag("products");

  // 2. Start the ERP/PIM sync in the background without awaiting it.  The
  //    admin gets an instant response; the catalog may show slightly stale
  //    data for a few seconds.
  syncFromERP()
    .then(() => {
      // 3. After the sync completes, invalidate again so the updated data
      //    (prices, stock, new SKUs) is picked up on the next request.
      revalidateTag("products");
    })
    .catch((err) => {
      console.error("Background ERP sync failed:", err);
    });
}

// ── Page ─────────────────────────────────────────────────────────────────

export default async function AdminPage() {
  let products;
  let sync;
  let total;

  try {
    const result = await getCachedProducts();
    products = result.items;
    sync = result.lastSync;
    total = result.total;
  } catch {
    // Fallback: if the cached read itself throws (e.g. DB unreachable) we
    // surface a meaningful message instead of crashing the whole page.
    return (
      <div style={{ maxWidth: 960, margin: "0 auto", padding: "2rem 1rem" }}>
        <h1>Admin Product Catalog</h1>
        <div
          style={{
            marginTop: "1rem",
            padding: "1rem",
            background: "#fef2f2",
            border: "1px solid #fecaca",
            borderRadius: 8,
            color: "#991b1b",
          }}
        >
          <strong>Failed to load catalog.</strong> Please try again or contact
          support.
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 960, margin: "0 auto", padding: "2rem 1rem" }}>
      {/* ── Header ─────────────────────────────────────────── */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
          flexWrap: "wrap",
          gap: "1rem",
          marginBottom: "1.5rem",
        }}
      >
        <div>
          <h1 style={{ margin: 0 }}>Admin Product Catalog</h1>
          <p style={{ color: "#6b7280", fontSize: "0.875rem", marginTop: "0.25rem" }}>
            Last synced:{" "}
            {new Date(sync).toLocaleString("en-US", {
              dateStyle: "medium",
              timeStyle: "short",
            })}
          </p>
        </div>

        <SyncForm syncAction={syncCatalog} />
      </div>

      {/* ── Empty state ────────────────────────────────────── */}
      {products.length === 0 ? (
        <div
          style={{
            padding: "3rem 1rem",
            textAlign: "center",
            color: "#6b7280",
            border: "2px dashed #d1d5db",
            borderRadius: 8,
          }}
        >
          <p style={{ fontSize: "1.125rem", fontWeight: 600 }}>
            No products found
          </p>
          <p style={{ marginTop: "0.25rem" }}>
            Run a catalog sync to pull in products from your ERP/PIM.
          </p>
        </div>
      ) : (
        <>
          {/* ── Product table ───────────────────────────────── */}
          <div style={{ overflowX: "auto" }}>
            <table
              style={{
                width: "100%",
                borderCollapse: "collapse",
                fontSize: "0.875rem",
              }}
            >
              <thead>
                <tr style={{ background: "#f9fafb", textAlign: "left" }}>
                  <th style={thStyle}>SKU</th>
                  <th style={thStyle}>Name</th>
                  <th style={{ ...thStyle, textAlign: "right" }}>Price</th>
                  <th style={{ ...thStyle, textAlign: "right" }}>Stock</th>
                  <th style={thStyle}>Status</th>
                </tr>
              </thead>
              <tbody>
                {products.map((product) => (
                  <tr
                    key={product.id}
                    style={{ borderBottom: "1px solid #e5e7eb" }}
                  >
                    <td style={tdStyle}>
                      <code style={{ fontSize: "0.8rem" }}>{product.sku}</code>
                    </td>
                    <td style={tdStyle}>{product.name}</td>
                    <td style={{ ...tdStyle, textAlign: "right" }}>
                      ${product.price.toFixed(2)}
                    </td>
                    <td style={{ ...tdStyle, textAlign: "right" }}>
                      <span
                        style={{
                          color: product.stock === 0 ? "#dc2626" : undefined,
                          fontWeight: product.stock === 0 ? 600 : undefined,
                        }}
                      >
                        {product.stock}
                      </span>
                    </td>
                    <td style={tdStyle}>
                      <span
                        style={{
                          display: "inline-block",
                          padding: "2px 8px",
                          borderRadius: 999,
                          fontSize: "0.75rem",
                          fontWeight: 600,
                          textTransform: "uppercase",
                          letterSpacing: "0.05em",
                          background:
                            product.status === "active" ? "#dcfce7" : "#fef3c7",
                          color:
                            product.status === "active" ? "#166534" : "#92400e",
                        }}
                      >
                        {product.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <p style={{ color: "#6b7280", fontSize: "0.875rem", marginTop: "0.75rem" }}>
            {total} product{total !== 1 ? "s" : ""}
          </p>
        </>
      )}

      {/* ── Caching info (visible in dev for debugging) ────── */}
      {process.env.NODE_ENV === "development" && (
        <details
          style={{
            marginTop: "2rem",
            padding: "0.75rem",
            background: "#f4f4f5",
            borderRadius: 6,
            fontSize: "0.8rem",
            color: "#71717a",
          }}
        >
          <summary style={{ cursor: "pointer", fontWeight: 600 }}>
            Cache info (dev only)
          </summary>
          <p style={{ marginTop: "0.5rem" }}>
            Catalog is cached under tag <code>products</code>. The sync action
            calls <code>revalidateTag(&quot;products&quot;)</code> to invalidate
            it — the next request re-fetches from the database.
          </p>
        </details>
      )}
    </div>
  );
}

